class BankingAppViewController: UIViewController {
    
    @IBOutlet weak var balanceLabel: UILabel!
    
    private var accountBalance: Double = 0.0
    
    override func viewDidLoad() {
        super.viewDidLoad()
        updateBalanceDisplay()
    }
    
    func processTransaction(amount: Double, isDeposit: Bool) {
        if isDeposit {
            accountBalance += amount
        } else if amount <= accountBalance {
            accountBalance -= amount
        } else {
            print("Insufficient funds")
            return
        }
        
        updateBalanceDisplay()
    }
    
    private func updateBalanceDisplay() {
        balanceLabel.text = "Account Balance: \(formatCurrency(accountBalance))"
    }
    
    private func formatCurrency(_ amount: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = Locale(identifier: "en_US")
        return formatter.string(from: NSNumber(value: amount)) ?? "$0.00"
    }
}